class Solution(object):
    def numberOfWays(self, n, x):
        MOD = 10**9 + 7
        dp = [0] * (n + 1)
        dp[0] = 1
        i = 1
        while i ** x <= n:
            pw = i ** x
            for j in range(n, pw - 1, -1):
                dp[j] = (dp[j] + dp[j - pw]) % MOD
            i += 1
        return dp[n]
